mapper.select:
SELECT DISTINCT RW.TBL_RESTOCK_WAIT_ID, SP.TBL_SO_M_ID, SM.SO_NO, SM.SO_TYPE, DBO.F_COL_NM('A', 'COMM', 'SO_ORDR_TYPE', SM.SO_TYPE) AS SO_TYPE_NM, SM.SO_STAT_CD, DBO.F_COL_NM('A', 'COMM', 'SO_STAT_CD', SM.SO_STAT_CD) AS SO_STAT_CD_NM, SP.PROD_CD, SP.PROD_NM, SP.QTY AS RETURN_QTY, RW.INBOUND_YN, RW.INBOUND_DT, RW.INBOUND_USER, RW.INBOUND_TIME, SM.AGNT_CD, AG.AGNT_NM, SM.ACPT_ER, SM.ACPT_TEL1, SM.ACPT_TEL2, SM.POST_CD, SM.ADDR1, SM.ADDR2, SM.DC_CD, DC.DC_NM, SM.ORDR_INPT_DT, SM.RCPT_DT, SM.RQST_DT, SM.DLVY_CNFM_DT, SM.MALL_CD, SM.BRAND, SM.REF_SO_NO, SM.DLVY_RQST_MSG, SM.CUST_SPCL_TXT, SM.SAVE_TIME, UM.USER_NM AS INST_ER FROM TBL_SO_P SP INNER JOIN TBL_SO_M SM ON SP.TBL_SO_M_ID = SM.TBL_SO_M_ID INNER JOIN TBL_RESTOCK_WAIT RW ON SP.TBL_SO_M_ID = RW.TBL_SO_M_ID AND SP.PROD_CD = RW.PROD_CD LEFT JOIN TBL_AGENCY_M AG ON SM.AGNT_CD = AG.AGNT_CD LEFT JOIN TBL_LGST_DC_M DC ON SM.DC_CD = DC.DC_CD LEFT JOIN TBL_INST_PLAN_M IP ON SM.TBL_SO_M_ID = IP.TBL_SO_M_ID LEFT JOIN TBL_USER_M UM ON IP.TBL_USER_M_ID = UM.TBL_USER_M_ID WHERE 1=1 AND SM.SO_STAT_CD NOT IN ('0000', '1900') AND SP.USE_YN = 'Y'
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.DLVY_CNFM_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.DLVY_CNFM_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.AGNT_CD IN
#{agnt}
AND SM.DC_CD IN
#{dc}
AND SM.SO_NO IN
#{so}
AND SM.SO_TYPE IN
#{soType}
AND SM.ACPT_ER LIKE '%' + #{acptNm} + '%'
AND (SM.ACPT_TEL1 LIKE '%' + #{acptTel} + '%' OR SM.ACPT_TEL2 LIKE '%' + #{acptTel} + '%')
AND SP.PROD_CD IN
#{prod}
AND SP.PROD_NM LIKE '%' + #{prodNmSrch} + '%'
AND (SM.ADDR1 LIKE '%' + #{srchAddr} + '%' OR SM.ADDR2 LIKE '%' + #{srchAddr} + '%')
AND RW.INBOUND_YN = #{inboundStatus}
AND SM.SO_STAT_CD = #{soStatCd}
ORDER BY SM.SAVE_TIME DESC
